// // This module implements a 16-bit shift register that captures a serial input signal (rx_in) with shift functionality controlled by a clock (clk) and a control signal (brg_en). On each clock cycle, if brg_en is deasserted, the shift register shifts in the new input bit from rx_in while shifting out the most significant bit, effectively moving the contents of the register to the left. The output signals, shift_0 and shift_15, indicate the current values of the least and most significant bits of the register, respectively. Upon a reset (rst), the register initializes to all zeros (16'h0000).
module top_module(input wire rx_in, clk, rst, brg_en, 
		output wire shift_0, shift_15);reg [15:0] shift_reg, next_shift_reg;

	assign shift_15 = shift_reg[15];
	assign shift_0 = shift_reg[0];

	always @(posedge clk, posedge rst) begin
		if (rst) begin
			shift_reg <= 16'hFFFF;
		end else begin
			shift_reg <= next_shift_reg;
		end
	end

	always @(*) begin
		if (brg_en) begin
			next_shift_reg <= {rx_in, shift_reg[15:1]};
		end else begin
			next_shift_reg <= shift_reg;
		end
	end

endmodule
